<?require("Cart.php");DBinfo();Brand();Root();mysql_connect("$DBHost","$DBUser","$DBPass");$old=date("z")-1;mysql("$DBName","DELETE FROM AUsers WHERE Date < $old");$result=mysql("$DBName","SELECT CartItemsID,Date FROM ACartItems");while ($row=mysql_fetch_row($result)) {$CII=$row[0];$CDa=$row[1];$pieces=explode(":",$CDa);$DCHK=$pieces[1];if ($DCHK < $old) {mysql("$DBName","DELETE FROM ACartItems WHERE CartItemsID = '$CII'");	}}////////echo "del";if ($UID != "") {$result=mysql("$DBName","SELECT * FROM AUsers WHERE User='$UID'");$num=mysql_num_rows($result);if ($num == "0") {$dt=date("YmdHis");$UID="$dt$REMOTE_ADDR";$date=date("z");mysql("$DBName","INSERT INTO AUsers VALUES ('$UID','$date')");Header("Location: $PHP_SELF?UID=$UID");}}if ($UID == "") {$dt=date("YmdHis");$UID="$dt$REMOTE_ADDR";$date=date("z");mysql("$DBName","INSERT INTO AUsers VALUES ('$UID','$date')");Header("Location: $PHP_SELF?UID=$UID");}commonHeader("$Company","Select a category");$result=mysql("$DBName","SELECT * FROM ACategory ORDER BY Category");fontFace("Arial","Select a category:<br><br>");echo "<ul>";while ($row  =  mysql_fetch_row($result)) {$Cat=$row[0];$CatID=$row[1];fontFace("Arial","<li><a href='$Relative/items.php?CA=$CatID&UID=$UID'>$Cat</a></li>");        }echo "</ul>";commonFooter($Relative,$UID);?>